using System.IO.Compression;
class ZipCreator
{
    void CreateArchive()
    {
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

arguments.new_str:
using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchiveEntry now sets the UTF-8 flag in
        // the entry header. The legacy Java consumer expects Shift-JIS, so we
        // specify the encoding explicitly to suppress the UTF-8 flag.
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create,
            Encoding.GetEncoding("shift_jis"));
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

